  const units = [
    makeUnit({ type: "execute-task", id: "M001/S01/T01", startedAt: 1e3, finishedAt: 2e3, cost: 0.05 }),
    makeUnit({ type: "execute-task", id: "M001/S01/T01", startedAt: 3e3, finishedAt: 4e3, cost: 0.06 }),
    makeUnit({ type: "execute-task", id: "M001/S01/T01", startedAt: 5e3, finishedAt: 6e3, cost: 0.07 })
  ];
  detectStuckLoops(units, anomalies);
  assert.equal(anomalies.length, 1, "3 distinct dispatches of the same unit should flag 1 anomaly");
  assert.equal(anomalies[0].type, "stuck-loop");
